from collections import OrderedDict
from typing import Dict, List

class IndexCache:
    def __init__(self, cache_size: int = 100):
        self.cache_size = cache_size
        self.cache: Dict[str, OrderedDict] = {}

    def get(self, index_file: str):
        if index_file not in self.cache:
            self.cache[index_file] = OrderedDict()
        return self.cache[index_file]

    def set(self, index_file: str, key: str, value):
        if index_file not in self.cache:
            self.cache[index_file] = OrderedDict()

        self.cache[index_file][key] = value

        if len(self.cache[index_file]) > self.cache_size:
            self.cache[index_file].popitem(last=False)

    def delete(self, index_file: str, key: str):
        if index_file in self.cache:
            if key in self.cache[index_file]:
                del self.cache[index_file][key]

                if not self.cache[index_file]:
